fn solve(grid: Vec<Vec<i64>>, k: i64) -> i64 {
    let m = grid.len();
    let n = grid[0].len();
    let k = k as usize;
    let mut teleport_map = vec![vec![Vec::new(); n]; m];
    for i in 0..m {
        for j in 0..n {
            for x in 0..m {
                for y in 0..n {
                    if grid[x][y] <= grid[i][j] {
                        teleport_map[i][j].push((x, y));
                    }
                }
            }
        }
    }
    let mut dist = vec![vec![vec![i64::MAX; k + 1]; n]; m];
    dist[0][0][0] = 0;
    let mut heap = BinaryHeap::new();
    heap.push((0, 0, 0, 0));
    let directions = [(0, 1), (1, 0)];
    while let Some((cost, i, j, t)) = heap.pop() {
        if cost > dist[i][j][t] {
            continue;
        }
        if i == m - 1 && j == n - 1 {
            return cost;
        }
        for (dx, dy) in directions {
            let ni = i as i32 + dx;
            let nj = j as i32 + dy;
            if ni >= 0 && ni < m as i32 && nj >= 0 && nj < n as i32 {
                let new_i = ni as usize;
                let new_j = nj as usize;
                let new_cost = cost + grid[new_i][new_j];
                if new_cost < dist[new_i][new_j][t] {
                    dist[new_i][new_j][t] = new_cost;
                    heap.push((new_cost, new_i, new_j, t));
                }
            }
        }
        if t < k {
